func solve: (nums: Array<Int64>) -> Int64 {
    n = nums.size()
    if n == 0 {
        return 0
    }

    full_mask: Int64 = (1 << 18) - 1
    value_to_index = MutableMap<Int64, Int64> {}
    for i from 0 to n-1 {
        value = nums.get(i)
        value_to_index.put(value, i)
    }

    function feasible(k: Int64) -> Bool {
        comp: Array<Int64> = Array.fill(n, -1)
        queue = Deque<Int64> {}

        for i from 0 to n-1 {
            if (nums.get(i) & k) == k && comp[i] == -1 {
                queue.clear()
                queue.push_back(i)
                comp[i] = i
                while not queue.empty() {
                    node = queue.front()
                    queue.pop_front()
                    a_val: Int64 = nums.get(node)
                    complement: Int64 = full_mask & ~a_val
                    w: Int64 = 0
                    while true {
                        candidate_value: Int64 = k | w
                        if candidate_value < n {
                            if value_to_index.containsKey(candidate_value) {
                                j_index: Int64 = value_to_index.get(candidate_value)
                                if comp[j_index] == -1 {
                                    comp[j_index] = comp[i]
                                    queue.push_back(j_index)
                                }
                            }
                        }
                        if w == complement {
                            break
                        }
                        w = (w - complement) & complement
                    }
                }
            }
        }

        for i from 0 to n-1 {
            if comp[i] == -1 {
                comp[i] = i
            }
        }

        seen_cycle: Array<Bool> = Array.fill(n, false)
        cycle_components = MutableMap<Int64, Int64> {}
        for i from 0 to n-1 {
            if not seen_cycle[i] {
                cycle: Array<Int64> = []
                cur = i
                while not seen_cycle[cur] {
                    seen_cycle[cur] = true
                    cycle.add(cur)
                    next = nums.get(cur)
                    next_index: Int64 = value_to_index.get(next)
                    cur = next_index
